"use client";

import React, { createContext, useContext, useState, useEffect } from 'react';
import { JournalState, Task, Habit, Note, DayData, Mood } from '../types/index';

const INITIAL_DAY_DATA: DayData = {
  date: new Date().toISOString(),
  mood: null,
  priorities: ['', '', ''],
  tasks: [],
  gratitude: ['', '', ''],
  devocionalVerse: "Porque yo sé muy bien los planes que tengo para ustedes...",
  devocionalRef: "Jeremías 29:11",
  devocionalReflection: '',
  prayerThanks: '',
  prayerAsk: '',
  prayerDecree: '',
};

const INITIAL_STATE: JournalState = {
  today: INITIAL_DAY_DATA,
  habits: [
    { id: '1', name: 'Beber agua', emoji: '💧', completedDays: Array(7).fill(false) },
    { id: '2', name: 'Meditar', emoji: '🧘‍♀️', completedDays: Array(7).fill(false) },
    { id: '3', name: 'Ejercicio', emoji: '🏃‍♀️', completedDays: Array(7).fill(false) },
  ],
  notes: [],
  streak: 0,
};

interface JournalContextType {
  state: JournalState;
  updateToday: (data: Partial<DayData>) => void;
  toggleHabitDay: (habitId: string, dayIndex: number) => void;
  addHabit: (name: string, emoji: string) => void;
  updateHabit: (id: string, name: string, emoji: string) => void; // NUEVA
  deleteHabit: (id: string) => void;
  addNote: (content: string) => void;
  deleteNote: (id: string) => void;
}

const JournalContext = createContext<JournalContextType | undefined>(undefined);
const STORAGE_KEY = 'diario_abigail_vfinal_stable';

export const JournalProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [state, setState] = useState<JournalState>(INITIAL_STATE);
  const [mounted, setMounted] = useState(false);

  useEffect(() => {
    setMounted(true);
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        const parsed: JournalState = JSON.parse(saved);
        const todayStr = new Date().toLocaleDateString();
        const savedDateStr = new Date(parsed.today.date).toLocaleDateString();
        
        if (todayStr !== savedDateStr) {
          setState({
            ...parsed,
            today: { ...INITIAL_DAY_DATA, date: new Date().toISOString() },
          });
        } else {
          setState({ ...INITIAL_STATE, ...parsed });
        }
      } catch (e) {
        console.error("Error loading state", e);
      }
    }
  }, []);

  useEffect(() => {
    if (mounted) {
      localStorage.setItem(STORAGE_KEY, JSON.stringify(state));
    }
  }, [state, mounted]);

  const updateToday = (data: Partial<DayData>) => {
    setState(prev => ({ ...prev, today: { ...prev.today, ...data } }));
  };

  const toggleHabitDay = (habitId: string, dayIndex: number) => {
    setState(prev => ({
      ...prev,
      habits: prev.habits.map(h => 
        h.id === habitId 
          ? { ...h, completedDays: h.completedDays.map((d, i) => i === dayIndex ? !d : d) }
          : h
      )
    }));
  };

  const addHabit = (name: string, emoji: string) => {
    const newHabit: Habit = {
      id: Date.now().toString(),
      name,
      emoji,
      completedDays: Array(7).fill(false)
    };
    setState(prev => ({ ...prev, habits: [...prev.habits, newHabit] }));
  };

  const updateHabit = (id: string, name: string, emoji: string) => {
    setState(prev => ({
      ...prev,
      habits: prev.habits.map(h => h.id === id ? { ...h, name, emoji } : h)
    }));
  };

  const deleteHabit = (id: string) => {
    setState(prev => ({ ...prev, habits: prev.habits.filter(h => h.id !== id) }));
  };

  const addNote = (content: string) => {
    const newNote: Note = {
      id: Date.now().toString(),
      date: new Date().toISOString(),
      content
    };
    setState(prev => ({ ...prev, notes: [newNote, ...prev.notes] }));
  };

  const deleteNote = (id: string) => {
    setState(prev => ({ ...prev, notes: prev.notes.filter(n => n.id !== id) }));
  };

  if (!mounted) return null;

  return (
    <JournalContext.Provider value={{ state, updateToday, toggleHabitDay, addHabit, updateHabit, deleteHabit, addNote, deleteNote }}>
      {children}
    </JournalContext.Provider>
  );
};

export const useJournal = () => {
  const context = useContext(JournalContext);
  if (!context) throw new Error('useJournal must be used within a JournalProvider');
  return context;
};
